  type Props = {
    /** Visual height of the logo. Width auto-scales from the viewBox. */
    height?: string | number;
  };
  let { height = 32 }: Props = $props();

  const heightStr = $derived(
    typeof height === "number" ? `${height}px` : String(height),
  );
</script>

